def _recruitee_board_exists(slug: str) -> bool:
    if not slug:
        return False
    try:
        response = requests.get(
            f"https://{slug}.recruitee.com/api/offers/",
            headers=HEADERS,
            timeout=8,
        )
        return response.status_code == 200
    except Exception:
